import React, { useCallback, useContext, useEffect, useMemo, useRef, useState } from 'react';
import { graphql, useStaticQuery } from 'gatsby';
import { navigate, useIntl } from 'gatsby-plugin-intl';
import { ClickAwayListener, InputBase, List, ListItem, ListItemText, Paper, Popper } from '@material-ui/core';
import { useFlexSearch } from 'react-use-flexsearch';
import { makeStyles } from '@material-ui/core/styles';
import classNames from 'classnames';

// Components
import Link from './Link';

// Contexts
import { CustomMenuContext } from '../themes/CustomMenuProvider';
import { isObjectNotEmpty } from '../utils/gatsby-frontend-helpers';

const useStyles = makeStyles((theme) => ({
    searchWrapper: {
        // marginLeft: 'auto',
        marginRight: '15px',
    },
    searchResultsWrapper: {
        boxShadow: '5px 5px 5px 0px #00000099',
    },
    searchInput: {
        fontSize: '16px',
        background: '#00000019',
        borderRadius: '4px',
        paddingRight: '10px',
        paddingLeft: '10px',
        paddingTop: '4px',
        marginBottom: '4px',
        ...theme?.palette?.type === 'light' && {
            color: '#ffffff',
        },
    },
    searchResultsPopper: {
        marginTop: '5px',
        zIndex: 1300,
        minWidth: '300px',
    },
    searchResultsItem: {
        cursor: 'pointer',
    },
    searchResultsPaper: {
        maxWidth: '450px',
        marginTop: '12px',
    },
    searchResultsLink: {
        textDecoration: 'none',
        '&:hover': {
            textDecoration: 'none',
        },
    },
}));

const SearchBar = ({ className }) => {
    const data = useStaticQuery(graphql`
        query SearchIndexQuery {
            localSearchBar {
                index
                store
            }
        }
    `);

    const classes = useStyles();
    const [query, setQuery] = useState('');
    const [showResults, setShowResults] = useState(true);
    const [selectedItem, setSelectedItem] = useState({});
    const [anchorEl, setAnchorEl] = React.useState(null);
    const { setIsShowingDrawer } = useContext(CustomMenuContext);
    const intl = useIntl();
    const ref = useRef();

    const flexSearchResults = useFlexSearch(
        query,
        data.localSearchBar.index,
        data.localSearchBar.store
    );

    const results = useMemo(() => {
        const filteredResults = flexSearchResults
            .filter((result) => result.locale === intl.locale)
            .slice(0, 5);

        if (query) {
            return [
                ...filteredResults,
                {
                    id: 'search-for-query-bogus-id',
                    locale: intl.locale,
                    path: `/search/${query}/`,
                    title: intl.formatMessage(
                        { id: 'search_for_query' },
                        { query }
                    ),
                    tags: [],
                },
            ];
        }

        return filteredResults;
    }, [flexSearchResults, intl.locale, query]);

    const open = Boolean(anchorEl);
    const handleFocus = useCallback((event) => {
        setAnchorEl(event.currentTarget);
        setShowResults(true);
    },
    []);

    const handleSearchResultClicked = useCallback(() => {
        setQuery('');
        setAnchorEl(null);
        setIsShowingDrawer(false);
    }, [setIsShowingDrawer]);

    const handleSearchKeyPressed = useCallback((ev) => {
        // Enter
        if (ev.keyCode === 13) {
            if (query) {
                setQuery('');
                if (anchorEl !== null) {
                    anchorEl.blur();
                    setAnchorEl(null);
                }

                setIsShowingDrawer(false);
                if (isObjectNotEmpty(selectedItem)) {
                    navigate(selectedItem.path);
                } else {
                    navigate(`/search/${query}`);
                }
            }
        } else if (ev.keyCode === 40) {
            // Down
            const currIndex = results.findIndex((result) => result.id === selectedItem.id);
            const newSelected = results[currIndex + 1];
            if (newSelected) {
                setSelectedItem(newSelected);
            }
        } else if (ev.keyCode === 38) {
            // Up
            const currIndex = results.findIndex((result) => result.id === selectedItem.id);
            const newSelected = results[currIndex - 1];
            if (isObjectNotEmpty(newSelected)) {
                setSelectedItem(newSelected);
            }
        } else if (ev.keyCode === 27) {
            // Escape
            setQuery('');
        }
    }, [anchorEl, query, results, selectedItem, setIsShowingDrawer]);

    const handleOnClickOutside = useCallback(() => {
        setShowResults(false);
    }, []);

    useEffect(() => {
        setSelectedItem({});
    }, [query]);

    return (
        <ClickAwayListener onClickAway={handleOnClickOutside}>
            <div
                className={classNames(className, classes.searchWrapper)}
            >
                <InputBase
                    className={classes.searchInput}
                    onKeyDown={handleSearchKeyPressed}
                    onChange={(ev) => {
                        setQuery(ev.target.value);
                    }}
                    onFocus={handleFocus}
                    placeholder={intl.formatMessage({ id: 'search_placeholder' })}
                    value={query}
                    // onClick={() => setShowResults(true)}
                />
                {showResults && results.length !== 0 && (
                    <Popper
                        ref={ref}
                        open={open}
                        className={classes.searchResultsPopper}
                        anchorEl={anchorEl}
                    >
                        <Paper className={classes.searchResultsPaper}>
                            <List className={classes.searchResultsWrapper}>
                                {results.map((result) => (
                                    <ListItem
                                        className={classes.searchResultsItem}
                                        key={result.id}
                                        selected={selectedItem.id === result.id}
                                        onClick={() => {
                                            handleSearchResultClicked();
                                            navigate(result.path);
                                        }}
                                        onMouseEnter={() => {
                                            const newSelected = results.find((res) => res.id === result.id);
                                            if (newSelected) {
                                                setSelectedItem(newSelected);
                                            }
                                        }}
                                    >
                                        <Link
                                            to={result.path}
                                            className={classes.searchResultsLink}
                                            onClick={handleSearchResultClicked}
                                        >
                                            <ListItemText
                                            // primary={result.path}
                                                secondary={result.title}
                                            />
                                        </Link>
                                    </ListItem>
                                ))}
                            </List>
                        </Paper>
                    </Popper>
                )}
            </div>
        </ClickAwayListener>
    );
};

export default SearchBar;
