import React, { useCallback, useContext } from 'react';
import { makeStyles } from '@material-ui/core/styles';
import { Hidden, Drawer } from '@material-ui/core';

// Context
import { CustomMenuContext } from '../themes/CustomMenuProvider';

// Components
import MenuItems from './MenuItems';
import Link from './Link';
import SiteLogo from './SiteLogo';
import SearchBar from './SearchBar';

const useStyles = makeStyles((theme) => ({
    menuItemsList: {
        width: 250,
    },
    homeMenuLink: {
        margin: '10px',
    },
    searchWrapper: {
        margin: '0 auto',
    },
    drawer: {
        ...theme?.palette?.type === 'light' && {
            backgroundColor: '#1f285a',
        },
    },
    logo: {
        marginLeft: '10px',
    },
}));

function SiteDrawer() {
    const { isShowingDrawer, setIsShowingDrawer } = useContext(CustomMenuContext);
    const classes = useStyles();
    const closeDrawer = useCallback(() => setIsShowingDrawer(false), [setIsShowingDrawer]);

    return (
        <div key="left">
            <Drawer
                anchor="left"
                open={isShowingDrawer}
                onClose={closeDrawer}
                classes={{
                    paper: classes.drawer,
                }}
            >
                <div
                    className={classes.homeMenuLink}
                >
                    <Link
                        to="/"
                        onClick={closeDrawer}
                    >
                        <SiteLogo className={classes.logo} />
                    </Link>
                </div>
                <div
                    className={classes.menuItemsList}
                    role="presentation"
                >
                    <MenuItems
                        isDrawer
                        onItemClick={closeDrawer}
                    />
                </div>
                <Hidden smUp>
                    <SearchBar
                        className={classes.searchWrapper}
                    />
                </Hidden>
            </Drawer>
        </div>
    );
}

export default SiteDrawer;
