import React, { useContext } from 'react';
import { AppBar, Toolbar, Hidden } from '@material-ui/core';
import MenuIcon from '@material-ui/icons/Menu';
import { makeStyles } from '@material-ui/core/styles';
import { useIntl } from 'gatsby-plugin-intl';
import PropTypes from 'prop-types';
import { CustomMenuContext } from '../themes/CustomMenuProvider';

// Components
import ThemeToggler from './ThemeToggler';
import MenuItems from './MenuItems';
import Link from './Link';
import SiteLogo from './SiteLogo';
import SearchBar from './SearchBar';
import LanguageSelector from './LanguageSelector';

const useStyles = makeStyles((theme) => ({
    burgerMenuIcon: {
        marginRight: '15px',
        '&:hover': {
            cursor: 'pointer',
        },
        ...theme?.palette?.type === 'light' && {
            color: '#ffffff',
        },
    },
    rightItems: {
        marginLeft: 'auto',
        display: 'inline-flex',
    },
    appBar: {
        ...theme?.palette?.type === 'light' && {
            backgroundColor: '#3f51b5',
        },
    },
}));

function Topbar({
    showLanguageSelector = true,
    onLanguageChange,
}) {
    const classes = useStyles();
    const intl = useIntl();
    const { isShowingDrawer, setIsShowingDrawer } = useContext(CustomMenuContext);

    return (
        <AppBar
            color="default"
            position="sticky"
            className={classes.appBar}
        >
            <Toolbar>
                <Hidden mdUp>
                    <div className={classes.burgerMenuIcon}>
                        <MenuIcon
                            onClick={() => setIsShowingDrawer(!isShowingDrawer)}
                        />
                    </div>
                </Hidden>
                <Link to="/">
                    <SiteLogo />
                </Link>
                <Hidden smDown>
                    <MenuItems />
                </Hidden>
                <div className={classes.rightItems}>
                    <Hidden xsDown>
                        <SearchBar />
                    </Hidden>
                    {showLanguageSelector && (
                        <LanguageSelector
                            currentLocale={intl.locale}
                            onLanguageChange={onLanguageChange}
                        />
                    )}
                    <ThemeToggler />
                </div>
            </Toolbar>
        </AppBar>
    );
}

Topbar.propTypes = {
    showLanguageSelector: PropTypes.bool,
};

export default Topbar;
