import React from 'react';
import { List, ListItem, ListItemText, Typography } from '@material-ui/core';
import { useIntl } from 'gatsby-plugin-intl';
import { makeStyles } from '@material-ui/core/styles';
import classNames from 'classnames';
import Link from './Link';

const useStyles = makeStyles((theme) => ({
    drawerList: {
        display: 'block',
    },
    menuLink: {
        fontSize: '1.25rem;',
        ...theme?.palette?.type === 'light' && {
            color: '#ffffff',
        },
    },
}));

function MenuItems({
    isDrawer = false,
    onItemClick = () => {},
}) {
    const classes = useStyles();
    const intl = useIntl();

    return (
        <List
            component="nav"
        >
            <ListItem
                component="div"
                className={classNames({
                    [classes.drawerList]: isDrawer,
                })}
            >
                <ListItemText inset>
                    <Link
                        to="/blog"
                        onClick={onItemClick}
                    >
                        <Typography
                            className={classes.menuLink}
                            color="textPrimary"
                            variant="subtitle1"
                        >
                            {intl.formatMessage({ id: 'blog' })}
                        </Typography>
                    </Link>
                </ListItemText>
                <ListItemText inset>
                    <Link
                        to="/projects"
                        onClick={onItemClick}
                    >
                        <Typography
                            className={classes.menuLink}
                            color="textPrimary"
                            variant="subtitle1"
                        >
                            {intl.formatMessage({ id: 'projects_page.title' })}
                        </Typography>
                    </Link>
                </ListItemText>
                <ListItemText inset>
                    <Link
                        to="/photos"
                        onClick={onItemClick}
                    >
                        <Typography
                            className={classes.menuLink}
                            color="textPrimary"
                            variant="subtitle1"
                        >
                            {intl.formatMessage({ id: 'photos' })}
                        </Typography>
                    </Link>
                </ListItemText>
                <ListItemText inset>
                    <Link
                        to="/about"
                        onClick={onItemClick}
                    >
                        <Typography
                            className={classes.menuLink}
                            color="textPrimary"
                            variant="subtitle1"
                        >
                            {intl.formatMessage({ id: 'about' })}
                        </Typography>
                    </Link>
                </ListItemText>
            </ListItem>
        </List>
    );
}

export default MenuItems;
